package com.company.supervision.application;import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;import com.company.supervision.application.scheduling.AdvancedScheduleService;import com.company.supervision.domain.model.TaskSchedule;import com.company.supervision.entity.dto.schedule.ScheduleRule;import com.company.supervision.infrastructure.repository.ScheduleMapper;import jakarta.annotation.PostConstruct;import lombok.extern.slf4j.Slf4j;import org.springframework.stereotype.Service;@Service @Slf4j public class SchedulerAppService{private final ScheduleMapper mapper;private final AdvancedScheduleService advanced;public SchedulerAppService(org.quartz.Scheduler ignored,ScheduleMapper m,AdvancedScheduleService a){mapper=m;advanced=a;}public void register(Long taskId,String cron){ScheduleRule r=new ScheduleRule();r.setMode("CRON");r.setCronExpression(cron);advanced.register(taskId,r);}public void remove(Long taskId){advanced.remove(taskId);}@PostConstruct public void init(){for(TaskSchedule s:mapper.selectList(new LambdaQueryWrapper<TaskSchedule>().eq(TaskSchedule::getStatus,1)))try{advanced.restore(s);}catch(Exception e){log.error("Failed to restore task {}: {}",s.getTaskId(),e.getMessage());}}}